external_knowledge:
- 'sailing under a particular banner' refers to employees belonging to a specific group;
- 'ventured into exploring the cosmos of 'Type 3'' indicates evaluations focusing on a characteristic labeled as 'Type 3';
- 'celebrated for their journey through the universe of work assessments' implies gathering data on evaluations;
- 'marked their voyage with the stars' symbolizes collecting names and evaluation results.

sql:
SELECT AVG(predicted_score) AS average_predicted_score
FROM predictions
WHERE predicted_score > 90;

SELECT employee_id, first_name, last_name
FROM employees
WHERE group_id = (SELECT group_id FROM groups WHERE group_name = 'Group 17304');

SELECT e.first_name, e.last_name, e.job_title, p.predicted_score
FROM employees e
JOIN predictions p ON e.employee_id = p.employee_id;

SELECT AVG(strftime('%Y', 'now') - strftime('%Y', date_of_birth)) AS avg_age
FROM employees
WHERE group_id = 17304 AND date_of_birth IS NOT NULL;
